#!/bin/bash
# Upload CDN files lên https://github.com/6677028/blogger-cdn
# Cách dùng: GITHUB_TOKEN=ghp_xxx bash upload_cdn.sh

set -e
TOKEN="${GITHUB_TOKEN}"
REPO="6677028/blogger-cdn"

if [ -z "$TOKEN" ]; then
  echo "Lỗi: GITHUB_TOKEN chưa được set"
  echo "Cách lấy token: https://github.com/settings/tokens → New token → repo scope"
  exit 1
fi

echo "Uploading 17 files lên $REPO..."

echo -n "  highlight.js/11.9.0/highlight.min.js... "
curl -sf -X PUT "https://api.github.com/repos/$REPO/contents/highlight.js/11.9.0/highlight.min.js" \
  -H "Authorization: Bearer $TOKEN" \
  -H "Content-Type: application/json" \
  -d '{"message": "Add highlight.js/11.9.0/highlight.min.js", "content": ""}' > /dev/null && echo "✓" || echo "✗ (đã tồn tại hoặc lỗi)"

